A backend is a small struct of function pointers (C89 indirect calls — fine on i386; Phase 4's feat.c uses the same pattern). The protocol core knows only the interface. /* transport.h */
typedef struct Transport Transport; struct Transport { const char *name; /* "serial" | "tcp" | "mock" | ... — surfaced in ready message */ int kind; /* TRANSPORT_SERIAL | TRANSPORT_TCP | ... */ int flags; /* bit0: message-oriented (bypass LineBuffer); else byte-stream */ /* Connection vtable. Return: >0 bytes moved, 0 = orderly peer close, <0 = error. */ int (*read)(Transport *t, void *buf, int len); int (*write)(Transport *t, const void *buf, int len); void (*close)(Transport *t); /* Server lifecycle. NULL for point-to-point backends (serial). * For listeners (tcp): blocks for a client, returns a *connection* Transport * (may be `t` itself reused, or a distinct conn). NULL `accept` => one-shot peer. */ Transport *(*accept)(Transport *t); union { HANDLE handle; unsigned int sock; void *ptr; } io; /* backend-private */
}; /* Backend registry — enables agnostic auto-detect + future backends */
typedef struct { int kind; const char *name; int (*probe)(void); /* 1 if usable on this host */ int (*open)(const TransportConfig *cfg, Transport *out, char *err, int errSize);
} TransportBackend; int TransportOpen(const TransportConfig *cfg, Transport *out, char *err, int errSize);
int TransportWriteAll(Transport *t, const void *buf, int len); /* loops on short writes */
const char *TransportName(const Transport *t); Framing stays above the transport. Newline-delimited JSON (LineBuffer) sits in the core and is fed by whatever bytes a backend's read delivers. Reliable, ordered byte transports (serial, TCP, and later QUIC/RDMA) need no change. A genuinely message-oriented exotic backend sets flags bit0 so the core treats one message = one command and skips LineBuffer. This is the only concession the core makes to non-stream transports — everything else is the backend's problem (reliability, ordering, MTU). The main loop becomes transport- and lifecycle-agnostic: TransportOpen(&cfg, &listener, err, sizeof err);
for (;;) { Transport *conn = listener.accept ? listener.accept(&listener) : &listener; SendReady(conn); Serve(conn); /* read → LineBuffer → ProcessCommand(line, conn) */ if (conn != &listener) conn->close(conn); if (!listener.accept) break; /* serial: one peer, done */ /* tcp: loop back to accept the next client (single-client-sequential) */
}
listener.close(&listener);

