specs/process-ops.allium: entity Capabilities { is_win32s, is_win9x, is_nt, is_wow64: Boolean has_threads, has_job_objects, has_ctrl_events: Boolean has_pty, has_get_binary_type, has_query_full_image_name: Boolean
} entity Process { cmd_line: String cwd: String binary_type: pe32 | pe32_wow64 | ne16 | mz | shell | unknown capabilities: Capabilities status: not_started | running | exited | timed_out | spawn_failed killed_by: none | timeout | ctrl_break | memory_cap | cpu_cap transitions status { not_started -> running not_started -> spawn_failed running -> exited running -> timed_out terminal: exited, timed_out, spawn_failed }
} entity ExecResult { process: Process exit_code: Integer stdout_b64, stderr_b64: String stdout_truncated, stderr_truncated: Boolean duration_ms: Integer request_id: String status: ok | error error_reason: String when status = error transitions status { terminal: ok, error }
} entity PtyExecResult { process: Process exit_code: Integer output_b64: String output_kind: ansi | text output_truncated: Boolean duration_ms: Integer request_id: String status: ok | error error_reason: String when status = error transitions status { terminal: ok, error }
} rule ExecSpawnSuccess { ... }
rule ExecSpawnFailed { ... }
rule ExecCompleted { ... }
rule ExecTimedOut { ... }
rule ExecOutputTruncated { ... }
rule ExecBusyRejected { ... }
rule ExecCtrlBreakKilled { ... } -- requires capabilities.has_ctrl_events
rule ExecMemoryCapKilled { ... } -- requires capabilities.has_job_objects
rule ExecCpuCapKilled { ... } -- requires capabilities.has_job_objects
rule PtyExecSpawnSuccess { ... } -- requires capabilities.has_pty
rule PtyExecCapabilityAbsent { ... } -- emits "pty not available on this Windows" when !capabilities.has_pty invariant ExitCodeOnSuccess { ... }
invariant TimedOutHasReason { ... }
invariant PtyOnlyWhenCapable { for r in PtyExecResults: r.status = ok implies r.process.capabilities.has_pty = true }
invariant Win32sNoJobObjects { for p in Processes: p.capabilities.is_win32s = true implies p.capabilities.has_job_objects = false } specs/catalog.allium: entity Catalog { path: String; loaded: Boolean; entry_count: Integer }
entity CatalogEntry { name: String; kind: shell_builtin | external; supports_win32s: Boolean }
rule CatalogLookupHit { ... }
rule CatalogLookupMiss { ... } -- emits "command not in catalog"
rule CatalogArgValid { ... }
rule CatalogArgInvalid { ... } -- emits "argument not allowed"
invariant LoadedCatalogHasEntries { for c in Catalogs: c.loaded implies c.entry_count > 0 } specs/mcp-protocol.allium: rewrite rule ExecCommand to gate on CatalogLookup then delegate to process-ops/ExecResult. Remove deferred ExecCommand.implementation line.
